context_template:
GOOGLE TOOLS DATA TO ANALYZE:
URL: {url}
Keywords: {keywords}

GOOGLE TRENDS DATA:
{trendsData}

PAGESPEED INSIGHTS DATA:
{pageSpeedData}

SEARCH CONSOLE DATA:
{searchConsoleData}

GOOGLE ANALYTICS DATA:
{analyticsData}

ANALYSIS CONSTRAINTS:
- Use only provided metrics and observations.
- Do not fabricate numbers, rankings, CTR, sessions, or conversion values.
- Distinguish measured facts from strategic inference.
- Prioritize high-impact actions that can be validated in the next measurement cycle.

format:
Return your analysis as a valid JSON object with this exact structure:
{
  "overall_opportunity_score": number (0-100),
  "market_trends_score": number (0-100),
  "performance_optimization_score": number (0-100),
  "revenue_potential_score": number (0-100),
  "data_coverage": {
    "trends": "provided" | "insufficient_data" | "missing",
    "pageSpeed": "provided" | "insufficient_data" | "missing",
    "searchConsole": "provided" | "insufficient_data" | "missing",
    "analytics": "provided" | "insufficient_data" | "missing"
  },
  "confidence": {
    "overall": number (0.0-1.0),
    "trends": number (0.0-1.0),
    "pageSpeed": number (0.0-1.0),
    "searchConsole": number (0.0-1.0),
    "analytics": number (0.0-1.0)
  },
  "trends_analysis": {
    "market_opportunities": [string],
    "keyword_opportunities": [string],
    "competitive_insights": [string],
    "growth_potential": string
  },
  "performance_analysis": {
    "current_performance": string,
    "optimization_opportunities": [string],
    "conversion_impact": string,
    "revenue_impact": string
  },
  "search_analysis": {
    "ranking_opportunities": [string],
    "content_gaps": [string],
    "traffic_potential": string,
    "conversion_opportunities": [string]
  },
  "analytics_insights": {
    "traffic_opportunities": [string],
    "conversion_optimization": [string],
    "revenue_optimization": [string],
    "growth_strategies": [string]
  },
  "top_opportunities": [
    {
      "opportunity": string,
      "impact": string,
      "effort": string,
      "roi_estimate": string,
      "timeline": string,
      "evidence_source": string
    }
  ],
  "action_plan": {
    "immediate_actions": [string],
    "short_term_goals": [string],
    "long_term_strategy": [string],
    "success_metrics": [string]
  }
}
